def route_recommendation(recommendation, policy):
    if policy.emergency_stop_active:
        return Blocked(reason="emergency stop")
    if recommendation.knowledge_state in {"unknown", "conflict"}:
        return HumanEscalation(evidence=recommendation.evidence)
