class ProductionReadinessReview:
    def evaluate(self, evidence_pack):
        critical = ["tests", "evals", "safety", "security", "recovery", "rollback"]
        failures = [name for name in critical if not evidence_pack.passed(name)]
        if failures:
            return Blocked(failures=failures)
        if not evidence_pack.owner or not evidence_pack.runbook or not evidence_pack.transfer_plan:
            return Blocked(failures=["ownership or operational evidence missing"] )
        return Ready(version=evidence_pack.release_version)
